'''
Bioinformatics stronghold
Title: Complementing a Strand of DNA 
'''
dna_str=""
'''
Steps
1.Take given input
2.Write complementary strands of each nucleotide
Complentary: A-T, T-A, C-G, G-C
3.Reverse the whole strand
'''
dna="ATCG"
comp="TAGC"
comp_str=str.maketrans(dna,comp)
rev_comp=dna_str.translate(comp_str)[::-1]
'''
Expected output according to the question:
The reverse complement s^c of s
'''
print(rev_comp)
